import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// getChatChannelMeta is imported per SDK convention but pulseboard meta is
// defined inline since the channel is not yet in the core ChatChannelId registry.
void getChatChannelMeta;

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging with named boards and direct messages.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (_cfg) => [],
      resolveAccount: (_cfg, _accountId) => ({
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: (_account) => false,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[${ctx.accountId}] starting PulseBoard provider`);
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text: _text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${Date.now()}`,
      });
    },
  },
});
