| `src/channels/plugins/types.adapters.ts` | `ChannelConfigAdapter`, `ChannelSetupAdapter`, `ChannelOutboundAdapter` interfaces |
| `src/channels/plugins/types.plugin.ts` | `ChannelPlugin` type |
