import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  getChatChannelMeta,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/core";

// getChatChannelMeta provides the canonical meta shape for registered channels.
// PulseBoard is not yet in the core ChatChannelId registry, so meta is defined
// inline below and all fields are supplied explicitly.
void (getChatChannelMeta as unknown);

/** Minimal resolved account shape for a PulseBoard connection. */
type ResolvedPulseBoardAccount = {
  accountId: string;
  name: string;
  enabled: boolean;
  configured: boolean;
};

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin<ResolvedPulseBoardAccount>({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard (Bulletin)",
        docsPath: "/channels/pulseboard",
        blurb:
          "Real-time bulletin board messaging; post to named boards or send direct messages.",
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      config: {
        listAccountIds: (_cfg) => ["default"],
        resolveAccount: (_cfg, accountId) => ({
          accountId: accountId ?? "default",
          name: accountId ?? "default",
          enabled: true,
          configured: false,
        }),
      },
      setup: {
        // Stub: return config unchanged until real onboarding is implemented.
        applyAccountConfig: ({ cfg }) => cfg,
      },
      messaging: {
        normalizeTarget: (target) => target.trim(),
      },
      gateway: {
        startAccount: async (ctx) => {
          ctx.log?.info(
            `[${ctx.account.accountId}] PulseBoard provider connecting to bulletin boards`,
          );
          return {
            stop: () => {
              ctx.log?.info(`[${ctx.account.accountId}] PulseBoard provider stopped`);
            },
          };
        },
      },
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ to, accountId }) => {
        const aid = accountId ?? "default";
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pulseboard-${aid}-${Date.now()}`,
        });
      },
    },
  });

